// DeepLinkActivity.java
package com.example.myapp;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import androidx.appcompat.app.AppCompatActivity;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.regex.Pattern;

public class DeepLinkActivity extends AppCompatActivity {
    private static final String TAG = "DeepLinkActivity";
    private static final String SCHEME = "myapp";
    
    private static final Set<String> ALLOWED_HOSTS = new HashSet<>(Arrays.asList(
        "profile",
        "payment",
        "admin"
    ));
    
    private static final Set<String> PUBLIC_ROUTES = new HashSet<>(Arrays.asList(
        "profile"
    ));
    
    private static final Set<String> AUTHENTICATED_ROUTES = new HashSet<>(Arrays.asList(
        "payment"
    ));
    
    private static final Set<String> ADMIN_ROUTES = new HashSet<>(Arrays.asList(
        "admin"
    ));
    
    private static final Pattern NUMERIC_PATTERN = Pattern.compile("^[0-9]+$");
    private static final Pattern ALPHANUMERIC_PATTERN = Pattern.compile("^[a-zA-Z0-9_-]+$");

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        
        Intent intent = getIntent();
        Uri data = intent.getData();
        
        if (data == null) {
            Log.e(TAG, "No deep link data received");
            navigateToHome();
            finish();
            return;
        }
        
        if (!handleDeepLink(data)) {
            navigateToHome();
        }
        
        finish();
    }
    
    private boolean handleDeepLink(Uri uri) {
        if (uri == null) {
            return false;
        }
        
        String scheme = uri.getScheme();
        if (!SCHEME.equals(scheme)) {
            Log.e(TAG, "Invalid scheme: " + scheme);
            return false;
        }
        
        String host = uri.getHost();
        if (TextUtils.isEmpty(host) || !ALLOWED_HOSTS.contains(host)) {
            Log.e(TAG, "Invalid or unauthorized host: " + host);
            return false;
        }
        
        if (!authorizeRoute(host)) {
            Log.e(TAG, "Authorization failed for route: " + host);
            showUnauthorizedMessage();
            return false;
        }
        
        switch (host) {
            case "profile":
                return handleProfileRoute(uri);
            case "payment":
                return handlePaymentRoute(uri);
            case "admin":
                return handleAdminRoute(uri);
            default:
                return false;
        }
    }
    
    private boolean authorizeRoute(String route) {
        if (PUBLIC_ROUTES.contains(route)) {
            return true;
        }
        
        if (AUTHENTICATED_ROUTES.contains(route)) {
            return isUserAuthenticated();
        }
        
        if (ADMIN_ROUTES.contains(route)) {
            return isUserAdmin();
        }
        
        return false;
    }
    
    private boolean handleProfileRoute(Uri uri) {
        String path = uri.getPath();
        if (TextUtils.isEmpty(path)) {
            return false;
        }
        
        String[] segments = path.split("/");
        if (segments.length < 2) {
            return false;
        }
        
        String userId = segments[1];
        if (!isValidUserId(userId)) {
            Log.e(TAG, "Invalid user ID format: " + userId);
            return false;
        }
        
        Intent profileIntent = new Intent(this, ProfileActivity.class);
        profileIntent.putExtra("user_id", userId);
        profileIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        startActivity(profileIntent);
        return true;
    }
    
    private boolean handlePaymentRoute(Uri uri) {
        String path = uri.getPath();
        if (TextUtils.isEmpty(path)) {
            return false;
        }
        
        String[] segments = path.split("/");
        if (segments.length < 2) {
            return false;
        }
        
        String action = segments[1];
        if (!"confirm".equals(action)) {
            Log.e(TAG, "Invalid payment action: " + action);
            return false;
        }
        
        String transactionId = uri.getQueryParameter("transaction_id");
        if (!isValidTransactionId(transactionId)) {
            Log.e(TAG, "Invalid or missing transaction ID");
            return false;
        }
        
        if (!verifyTransactionOwnership(transactionId)) {
            Log.e(TAG, "User does not own this transaction");
            return false;
        }
        
        Intent paymentIntent = new Intent(this, PaymentActivity.class);
        paymentIntent.putExtra("action", action);
        paymentIntent.putExtra("transaction_id", transactionId);
        paymentIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        startActivity(paymentIntent);
        return true;
    }
    
    private boolean handleAdminRoute(Uri uri) {
        String path = uri.getPath();
        if (TextUtils.isEmpty(path)) {
            return false;
        }
        
        String[] segments = path.split("/");
        if (segments.length < 2) {
            return false;
        }
        
        String section = segments[1];
        if (!"settings".equals(section)) {
            Log.e(TAG, "Invalid admin section: " + section);
            return false;
        }
        
        Intent adminIntent = new Intent(this, AdminActivity.class);
        adminIntent.putExtra("section", section);
        adminIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        startActivity(adminIntent);
        return true;
    }
    
    private boolean isValidUserId(String userId) {
        if (TextUtils.isEmpty(userId)) {
            return false;
        }
        
        if (userId.length() > 20) {
            return false;
        }
        
        return NUMERIC_PATTERN.matcher(userId).matches();
    }
    
    private boolean isValidTransactionId(String transactionId) {
        if (TextUtils.isEmpty(transactionId)) {
            return false;
        }
        
        if (transactionId.length() > 50) {
            return false;
        }
        
        return ALPHANUMERIC_PATTERN.matcher(transactionId).matches();
    }
    
    private boolean isUserAuthenticated() {
        SessionManager sessionManager = SessionManager.getInstance(this);
        return sessionManager.isLoggedIn();
    }
    
    private boolean isUserAdmin() {
        SessionManager sessionManager = SessionManager.getInstance(this);
        return sessionManager.isLoggedIn() && sessionManager.isAdmin();
    }
    
    private boolean verifyTransactionOwnership(String transactionId) {
        SessionManager sessionManager = SessionManager.getInstance(this);
        if (!sessionManager.isLoggedIn()) {
            return false;
        }
        
        String currentUserId = sessionManager.getUserId();
        TransactionRepository repository = new TransactionRepository(this);
        return repository.isTransactionOwnedByUser(transactionId, currentUserId);
    }
    
    private void navigateToHome() {
        Intent homeIntent = new Intent(this, MainActivity.class);
        homeIntent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        startActivity(homeIntent);
    }
    
    private void showUnauthorizedMessage() {
        Intent intent = new Intent(this, UnauthorizedActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        startActivity(intent);
    }
}

// SessionManager.java
package com.example.myapp;

import android.content.Context;
import android.content.SharedPreferences;

public class SessionManager {
    private static final String PREF_NAME = "UserSession";
    private static final String KEY_IS_LOGGED_IN = "isLoggedIn";
    private static final String KEY_USER_ID = "userId";
    private static final String KEY_IS_ADMIN = "isAdmin";
    
    private static SessionManager instance;
    private SharedPreferences prefs;
    
    private SessionManager(Context context) {
        prefs = context.getApplicationContext().getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }
    
    public static synchronized SessionManager getInstance(Context context) {
        if (instance == null) {
            instance = new SessionManager(context);
        }
        return instance;
    }
    
    public boolean isLoggedIn() {
        return prefs.getBoolean(KEY_IS_LOGGED_IN, false);
    }
    
    public String getUserId() {
        return prefs.getString(KEY_USER_ID, null);
    }
    
    public boolean isAdmin() {
        return prefs.getBoolean(KEY_IS_ADMIN, false);
    }
    
    public void setLogin(String userId, boolean isAdmin) {
        SharedPreferences.Editor editor = prefs.edit();
        editor.putBoolean(KEY_IS_LOGGED_IN, true);
        editor.putString(KEY_USER_ID, userId);
        editor.putBoolean(KEY_IS_ADMIN, isAdmin);
        editor.apply();
    }
    
    public void logout() {
        SharedPreferences.Editor editor = prefs.edit();
        editor.clear();
        editor.apply();
    }
}

